public class SettingsHolder {

    private Settings settings;

    public Settings get() {
        if (settings == null) {
            synchronized (this) {
                if (settings == null) {
                    settings = load();
                }
            }
        }
        return settings;
    }

    private Settings load() {
        return new Settings();
    }

    public static final class Settings {
    }
}
